code = """import json, re, os, pandas as pd
# load alive BRCA breast records
path_alive = var_call_ZbGvoEwtZPEN2fUZMWW8Birh
if isinstance(path_alive,str) and path_alive.endswith('.json') and os.path.exists(path_alive):
    alive_recs = json.load(open(path_alive))
else:
    alive_recs = path_alive

# load CDH1 mutated participants
path_mut = var_call_xmFvHkBytlqVMRFbhP9WQwYO
if isinstance(path_mut,str) and path_mut.endswith('.json') and os.path.exists(path_mut):
    mut_recs = json.load(open(path_mut))
else:
    mut_recs = path_mut
mut_set = set(r['ParticipantBarcode'] for r in mut_recs)

# extract TCGA barcode from patient_description
rows=[]
for r in alive_recs:
    desc = (r.get('patient_description') or r.get('Patient_description') or '')
    m = re.search(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', desc)
    if not m:
        continue
    barcode = m.group(1)
    hist = r.get('histological_type')
    rows.append({'ParticipantBarcode': barcode, 'histological_type': hist, 'mut': barcode in mut_set})

df = pd.DataFrame(rows)
# compute counts per hist type
agg = df.groupby('histological_type', dropna=False).agg(total=('ParticipantBarcode','nunique'), mut=('mut','sum')).reset_index()
agg['pct_mut'] = (agg['mut'] / agg['total'] * 100).round(2)
agg = agg.sort_values(['pct_mut','mut','total'], ascending=[False,False,False])
res = agg.head(3).to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(res))"""

